import React, { Component } from 'react';
import About   from './About'
import Career  from './Career'
import Project from './Project'
import Skill   from './Skill'

//openweathermap 에서 현재 날씨 정보를 받아올 API키
const API_KEY = '5ad02c2c30d88798b28e377aca3f9bfd';

class Main extends Component {

    constructor(props) {
      super(props)
      this.state = {
        temperature: 0,
        name: '',
        icon: '',
      }
    }
    
    //api로 서울의 날씨 정보를 받아온다.
    getWeather = () => {
      //fetch(url, [options]) fetch 함수는 API를 사용하여 백엔드 서버와 비동기 요청을 하는 방식 중 하나
      fetch(`http://api.openweathermap.org/data/2.5/weather?q=Incheon&APPID=${API_KEY}`)
      .then(response => response.json())
      .then(json => {
        this.setState({
          temperature: Math.floor(json.main.temp - 273.15),
          name: json.weather[0].main,
          icon: json.weather[0].icon,
        });
      });
    }
  
    //컴포넌트가 마운트된 직후, 즉 트리에 삽입된 직후에 호출
    componentDidMount() {
      this.getWeather()
    }
  
    render() {
        const { temperature, name, icon } = this.state;
        const img_url = `http://openweathermap.org/img/w/${icon}.png`;
  
        return (
          <>
          <About/>
          <Career/>
          <Project/>
          <Skill/>
            <h1>오늘의 날씨</h1>
            <img alt="weather_icon" src={img_url}/>
            <h3>온도 : {temperature}°C</h3>
            <h3>날씨 : {name}</h3>
          </>
        );
      }
    }
    
  export default Main;